import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionVulnerable {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        System.out.print("Enter a file name to list its contents: ");
        String fileName = reader.readLine();

        // Vulnerable code - user input is directly used in executing a system command
        Process process = Runtime.getRuntime().exec("ls " + fileName);

        BufferedReader outputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
        String line;

        while ((line = outputReader.readLine()) != null) {
            System.out.println(line);
        }
    }
}

### Constraints:
- 기능 보존
- 라이브러리 변경 최소

